import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../components/ui/card';
import { Button } from '../components/ui/button';
import { Badge } from '../components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '../components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../components/ui/tabs';
import { 
  Calendar, 
  Clock, 
  Users, 
  Search, 
  Plus,
  Filter,
  ArrowLeft,
  Phone,
  CheckCircle,
  AlertCircle,
  FileText,
  User
} from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import { getTodayAppointments, mockAppointments } from '../services/mockData';
import LoadingSpinner from '../components/ui/LoadingSpinner';
import { toast } from 'sonner';

export default function AppointmentScheduling() {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [todayAppointments, setTodayAppointments] = useState([]);
  const [allAppointments, setAllAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [activeTab, setActiveTab] = useState('today');
  
  // Check if user is patient for conditional rendering
  const isPatient = user?.role === 'patient';
  const isDoctor = user?.role === 'doctor';

  useEffect(() => {
    const loadAppointments = async () => {
      try {
        setLoading(true);
        
        if (isPatient) {
          // For patients, show their upcoming appointments
          const patientId = user?.id || 'patient-1';
          console.log('🔍 AppointmentScheduling: Loading for patientId:', patientId);
          console.log('👤 AppointmentScheduling: User context:', user);
          
          const patientAppts = mockAppointments.filter(apt => apt.patientId === patientId);
          console.log('📅 AppointmentScheduling: Patient appointments:', patientAppts);
          setAllAppointments(patientAppts);
          
          // Filter today's appointments for patient
          const today = new Date().toISOString().split('T')[0];
          const todayAppts = patientAppts.filter(apt => apt.date === today);
          setTodayAppointments(todayAppts);
        } else if (isDoctor) {
          // For doctors, show their patients' appointments
          const doctorId = user?.id || 'doc-1';
          console.log('🔍 AppointmentScheduling: Loading for doctorId:', doctorId);
          console.log('👤 AppointmentScheduling: User context:', user);
          
          // Load today's appointments
          const todayAppts = await getTodayAppointments(doctorId);
          console.log('📅 AppointmentScheduling: Today appointments:', todayAppts);
          setTodayAppointments(todayAppts);
          
          // Load all appointments for this doctor
          const allAppts = mockAppointments.filter(apt => apt.doctorId === doctorId);
          console.log('📋 AppointmentScheduling: All appointments:', allAppts);
          setAllAppointments(allAppts);
        }
      } catch (error) {
        console.error('Error loading appointments:', error);
        toast.error('Failed to load appointments');
      } finally {
        setLoading(false);
      }
    };

    loadAppointments();
  }, [user, isPatient, isDoctor]);

  const formatTime = (time) => {
    if (!time) return 'Time TBD';
    const [hours, minutes] = time.split(':');
    const hour = parseInt(hours);
    const ampm = hour >= 12 ? 'PM' : 'AM';
    const displayHour = hour % 12 || 12;
    return `${displayHour}:${minutes} ${ampm}`;
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'confirmed':
        return <CheckCircle className="w-4 h-4 text-green-500" />;
      case 'pending':
        return <Clock className="w-4 h-4 text-yellow-500" />;
      case 'cancelled':
        return <AlertCircle className="w-4 h-4 text-red-500" />;
      default:
        return <Clock className="w-4 h-4 text-gray-500" />;
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'confirmed':
        return 'bg-green-100 text-green-800 border-green-200';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'cancelled':
        return 'bg-red-100 text-red-800 border-red-200';
      default:
        return 'bg-gray-100 text-gray-800 border-gray-200';
    }
  };

  const handleAppointmentAction = (appointmentId, action) => {
    toast.success(`Appointment ${action} successfully!`);
  };

  const handleNavigateToTodayAppointments = () => {
    navigate('/app/doctor/today-appointments');
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-96">
        <LoadingSpinner size="lg" text="Loading appointments..." />
      </div>
    );
  }

  // Render patient view (appointment booking)
  if (isPatient) {
    return (
      <div className="space-y-6">
        {/* Patient Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">My Appointments</h1>
            <p className="text-gray-600">View your appointments and book new ones</p>
          </div>
          <Button 
            onClick={() => navigate('/app/patient/appointments/book')}
            className="bg-blue-600 hover:bg-blue-700 text-white flex items-center gap-2"
          >
            <Plus className="w-4 h-4" />
            Book New Appointment
          </Button>
        </div>

        {/* Patient Stats */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center gap-3">
                <Calendar className="w-8 h-8 text-blue-600" />
                <div>
                  <p className="text-sm text-gray-600">Upcoming</p>
                  <p className="text-2xl font-bold">
                    {allAppointments.filter(apt => new Date(apt.date) >= new Date()).length}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center gap-3">
                <CheckCircle className="w-8 h-8 text-green-600" />
                <div>
                  <p className="text-sm text-gray-600">Confirmed</p>
                  <p className="text-2xl font-bold">
                    {allAppointments.filter(apt => apt.status === 'confirmed').length}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
          
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center gap-3">
                <Clock className="w-8 h-8 text-yellow-600" />
                <div>
                  <p className="text-sm text-gray-600">Pending</p>
                  <p className="text-2xl font-bold">
                    {allAppointments.filter(apt => apt.status === 'pending').length}
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Patient Appointments List */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Calendar className="w-5 h-5" />
              Your Appointments
            </CardTitle>
            <CardDescription>
              View and manage your scheduled appointments
            </CardDescription>
          </CardHeader>
          <CardContent>
            {allAppointments.length === 0 ? (
              <div className="text-center py-12 text-gray-500">
                <Calendar className="w-16 h-16 mx-auto mb-4 text-gray-300" />
                <h3 className="text-lg font-medium mb-2">No appointments scheduled</h3>
                <p>Book your first appointment to get started</p>
                <Button 
                  className="mt-4 bg-blue-600 hover:bg-blue-700"
                  onClick={() => navigate('/app/patient/appointments/book')}
                >
                  Book Appointment
                </Button>
              </div>
            ) : (
              <div className="space-y-4">
                {allAppointments
                  .sort((a, b) => new Date(a.date) - new Date(b.date))
                  .map((appointment) => (
                  <Card key={appointment.id} className="border-l-4 border-l-blue-500">
                    <CardContent className="p-4">
                      <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
                        <div className="flex items-center gap-3">
                          <Calendar className="w-5 h-5 text-gray-500" />
                          <div>
                            <p className="font-semibold">{appointment.date ? new Date(appointment.date).toLocaleDateString() : 'Date TBD'}</p>
                            <p className="text-sm text-gray-500">{appointment.time ? formatTime(appointment.time) : 'Time TBD'}</p>
                          </div>
                        </div>

                        <div className="flex items-center gap-3">
                          <Avatar className="w-8 h-8">
                            <AvatarImage src={`https://api.dicebear.com/7.x/avataaars/svg?seed=doctor`} />
                            <AvatarFallback className="text-xs">DR</AvatarFallback>
                          </Avatar>
                          <div>
                            <h4 className="font-medium">Doctor</h4>
                            <p className="text-sm text-gray-600">{appointment.appointmentType || 'consultation'}</p>
                          </div>
                        </div>

                        <div className="col-span-1">
                          <p className="text-sm text-gray-600 line-clamp-2">
                            {appointment.symptoms || 'No symptoms specified'}
                          </p>
                        </div>

                        <div className="flex items-center justify-between">
                          <Badge className={getStatusColor(appointment.status)}>
                            {appointment.status}
                          </Badge>
                          <div className="flex gap-1">
                            <Button size="sm" variant="ghost">
                              <Phone className="w-4 h-4" />
                            </Button>
                            <Button size="sm" variant="ghost">
                              <FileText className="w-4 h-4" />
                            </Button>
                          </div>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    );
  }

  // Render doctor view (original functionality) 
  return (
    <div className="space-y-6">
      {/* Doctor Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Appointments</h1>
          <p className="text-gray-600">Manage your appointments and schedule</p>
        </div>
        <Button 
          onClick={handleNavigateToTodayAppointments}
          variant="outline"
          className="flex items-center gap-2"
        >
          <Calendar className="w-4 h-4" />
          View Today's Details
        </Button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <Calendar className="w-8 h-8 text-blue-600" />
              <div>
                <p className="text-sm text-gray-600">Today</p>
                <p className="text-2xl font-bold">{todayAppointments.length}</p>
              </div>
            </div>
          </CardContent>
        </Card>
        
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <CheckCircle className="w-8 h-8 text-green-600" />
              <div>
                <p className="text-sm text-gray-600">Confirmed</p>
                <p className="text-2xl font-bold">
                  {allAppointments.filter(apt => apt.status === 'confirmed').length}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
        
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <Clock className="w-8 h-8 text-yellow-600" />
              <div>
                <p className="text-sm text-gray-600">Pending</p>
                <p className="text-2xl font-bold">
                  {allAppointments.filter(apt => apt.status === 'pending').length}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>
        
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <Users className="w-8 h-8 text-purple-600" />
              <div>
                <p className="text-sm text-gray-600">Total</p>
                <p className="text-2xl font-bold">{allAppointments.length}</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Main Content Tabs */}
      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className="grid w-full grid-cols-2">
          <TabsTrigger value="today">Today's Schedule</TabsTrigger>
          <TabsTrigger value="all">All Appointments</TabsTrigger>
        </TabsList>

        {/* Today's Appointments Tab */}
        <TabsContent value="today" className="space-y-4">
          <Card>
            <CardHeader>
              <div className="flex items-center justify-between">
                <div>
                  <CardTitle className="flex items-center gap-2">
                    <Calendar className="w-5 h-5" />
                    Today's Schedule
                  </CardTitle>
                  <CardDescription>
                    {formatDate(new Date().toISOString())} • {todayAppointments.length} appointments
                  </CardDescription>
                </div>
                <Button 
                  variant="outline" 
                  onClick={handleNavigateToTodayAppointments}
                >
                  View Full Details
                </Button>
              </div>
            </CardHeader>
            <CardContent>
              {todayAppointments.length === 0 ? (
                <div className="text-center py-8 text-gray-500">
                  <Calendar className="w-12 h-12 mx-auto mb-4 text-gray-300" />
                  <p>No appointments scheduled for today</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {todayAppointments
                    .sort((a, b) => (a.time || '').localeCompare(b.time || ''))
                    .map((appointment) => (
                    <Card key={appointment.id} className="border-l-4 border-l-blue-500">
                      <CardContent className="p-4">
                        <div className="grid grid-cols-1 lg:grid-cols-4 gap-4">
                          {/* Time and Status */}
                          <div className="flex items-center gap-3">
                            <Clock className="w-5 h-5 text-blue-600" />
                            <div>
                              <p className="font-semibold">{formatTime(appointment.time)}</p>
                              <p className="text-sm text-gray-500">{appointment.duration || 30} min</p>
                            </div>
                          </div>

                          {/* Patient Info */}
                          <div className="flex items-center gap-3">
                            <Avatar className="w-10 h-10">
                              <AvatarImage src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${appointment.patientName || 'unknown'}`} />
                              <AvatarFallback>
                                {appointment.patientName ? appointment.patientName.split(' ').map(n => n[0]).join('') : 'UN'}
                              </AvatarFallback>
                            </Avatar>
                            <div>
                              <h4 className="font-semibold">{appointment.patientName || 'Unknown Patient'}</h4>
                              <p className="text-sm text-gray-600 capitalize">
                                {appointment.appointmentType || 'consultation'}
                              </p>
                            </div>
                          </div>

                          {/* Symptoms/Notes */}
                          <div className="space-y-1">
                            <p className="text-sm font-medium text-gray-700">Chief Complaint:</p>
                            <p className="text-sm text-gray-600 line-clamp-2">
                              {appointment.symptoms || 'No symptoms specified'}
                            </p>
                          </div>

                          {/* Status and Actions */}
                          <div className="flex items-center justify-between">
                            <div className="flex items-center gap-2">
                              {getStatusIcon(appointment.status)}
                              <Badge className={getStatusColor(appointment.status)}>
                                {appointment.status}
                              </Badge>
                            </div>
                            <div className="flex gap-2">
                              <Button 
                                size="sm" 
                                variant="outline"
                                onClick={() => handleAppointmentAction(appointment.id, 'started')}
                              >
                                Start
                              </Button>
                            </div>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* All Appointments Tab */}
        <TabsContent value="all" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Users className="w-5 h-5" />
                All Appointments
              </CardTitle>
              <CardDescription>
                Complete list of your appointments
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {allAppointments
                  .sort((a, b) => new Date(b.date || '1900-01-01') - new Date(a.date || '1900-01-01'))
                  .map((appointment) => (
                  <Card key={appointment.id} className="border-l-4 border-l-gray-300">
                    <CardContent className="p-4">
                      <div className="grid grid-cols-1 lg:grid-cols-5 gap-4">
                        <div className="flex items-center gap-3">
                          <Calendar className="w-5 h-5 text-gray-500" />
                          <div>
                            <p className="font-semibold">{appointment.date ? new Date(appointment.date).toLocaleDateString() : 'Date TBD'}</p>
                            <p className="text-sm text-gray-500">{appointment.time ? formatTime(appointment.time) : 'Time TBD'}</p>
                          </div>
                        </div>

                        <div className="flex items-center gap-3">
                          <Avatar className="w-8 h-8">
                            <AvatarImage src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${appointment.patientName || 'unknown'}`} />
                            <AvatarFallback className="text-xs">
                              {appointment.patientName ? appointment.patientName.split(' ').map(n => n[0]).join('') : 'UN'}
                            </AvatarFallback>
                          </Avatar>
                          <div>
                            <h4 className="font-medium">{appointment.patientName || 'Unknown Patient'}</h4>
                            <p className="text-sm text-gray-600">{appointment.appointmentType || 'consultation'}</p>
                          </div>
                        </div>

                        <div className="col-span-2">
                          <p className="text-sm text-gray-600 line-clamp-2">
                            {appointment.symptoms || 'No symptoms specified'}
                          </p>
                        </div>

                        <div className="flex items-center justify-between">
                          <Badge className={getStatusColor(appointment.status)}>
                            {appointment.status}
                          </Badge>
                          <div className="flex gap-1">
                            <Button size="sm" variant="ghost">
                              <Phone className="w-4 h-4" />
                            </Button>
                            <Button size="sm" variant="ghost">
                              <FileText className="w-4 h-4" />
                            </Button>
                          </div>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>

      </Tabs>
    </div>
  );
}
